            padding: "clamp(34px,5vw,48px) clamp(28px,5vw,44px)",
            boxShadow: "0 30px 90px rgba(0,0,0,0.55), inset 0 1px 0 rgba(255,255,255,0.06)",
            textAlign: "center",
